var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"따스한 햇살, 새들이 지저귀는 노랫소리......","JPN":"温かい日差し、鳥のさえずり……","ENG":"Ah, the warm sunlight... Chirping birds...","TWN":"溫暖的陽光，嘰嘰喳喳的小鳥……"},"stage":{"bg":"OFFICE_HEAD","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"일하기 정말 좋은 날이군!","JPN":"仕事日和の天気だな！","ENG":"What a perfect day to get to work!","TWN":"真是適合工作的好天氣啊！"},"stage":{"bg":"OFFICE_HEAD","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_TADA"},{"id":"L4_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"이런, 이럴 때가 아니지.","JPN":"こんな日にのんびりするのは勿体ない。","ENG":"Dear me, now's not the time to goof around.","TWN":"哎呀，現在不是偷懶的時候。"},"stage":{"bg":"OFFICE_HEAD","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"우리 직원들도 존경하는 사장님한테 얼른 돈을 벌어다 주고 싶어서 몸이 근질거리겠어.","JPN":"我が社の社員たちも尊敬する社長のために、稼ぎたくてウズウズしているだろうな。","ENG":"I'm sure my employees are itching to make money for their beloved boss.","TWN":"我們的員工應該迫不及待地要替他們尊敬的老闆賺錢了吧。"},"stage":{"bg":"OFFICE_HEAD","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"하하, 나도 참. 사무실로 간다는 게 실수로 공사장에 왔나 보군.","JPN":"ハハハ、私ったら。会社に行くつもりがうっかり工事現場に来てしまったようだな。","ENG":"Hah hah, silly me. I must have stumbled into a construction site instead of my office.","TWN":"哈哈，我也真是的，明明想著要去辦公室，怎麼來到了工地。"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"......아니, 잠깐.","JPN":"……いや、待て。","ENG":"... Hang on.","TWN":"……等等。"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"여기 떨어져 있는 건 관리부장 몰래 공금으로 만든 머신 갑 황금 트로피인데?","JPN":"ここに落ちているのは管理部長に内緒にしているマシーン甲黄金トロフィーじゃないか！？","ENG":"Isn't this the Golden Machine G.A.P. trophy that I secretly bought with office funds so the Manager wouldn't notice?","TWN":"這個東西不是瞞著管理部長偷偷用公款做成的甲·機器人黃金獎盃嗎？"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE"},{"id":"L16_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"어떻게 된 거지? 여기가 정말 우리 회사란 건가?","JPN":"どういうことだ？　ここは本当にうちの会社なのか？","ENG":"Why is it rolling on the floor like this? What happened here? Is this really my company?","TWN":"這是怎麼回事？難道這裡真的是我們公司？"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"사, 사장님! 출근하셨네요!","JPN":"しゃ、社長！　おはようございます！","ENG":"B-Boss! You're at work!","TWN":"老、老闆！你來了！"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"레나 양? 왜 그렇게 초췌한 얼굴인가?","JPN":"レナ君？　その疲れ切った顔はどうしたんだ？","ENG":"Lena? Why do you look so tired?","TWN":"蕾娜？妳看起來怎麼這麼憔悴？"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"실은 어제 관리부장님이 과로로 앓아 누우셨거든요.","JPN":"実は昨日、管理部長が過労で体調を崩しちゃったんです。","ENG":"The Manager had to take sick leave yesterday from overworking herself, you see.","TWN":"昨天管理部長因為過度勞累病倒了。"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"급한 일은 제가 맡겠다고 했는데, 관리부장님 업무량이 생각보다 훨씬 많아서 그만......","JPN":"急ぎの件は私が代わりにやることにしたんですが、管理部長の業務量が想像以上で……私もキャパオーバーに……","ENG":"I told her I could take care of the urgent stuff... Little did I know she had more work than I could imagine.","TWN":"於是暫時由我來接手部長的工作，可沒想到管理部長要處理的業務非常多，所以……"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"으음. 나쁜 소식이군.","JPN":"ふむ。それは良からぬ知らせだな。","ENG":"Hmm. That's bad news.","TWN":"唔，這可是個壞消息。"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L25_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"부사장이 이 꼴을 보면 아주 곤란한 일이 벌어지겠어.","JPN":"副社長にこの光景を見られたら、とんでもないことになりそうだ。","ENG":"I can't have the Vice President see this, or things will get real scary.","TWN":"萬一被副總看到，那就不好辦了。"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"들키기 전에 얼른 사무실 정리부터 하지. 나도 도울 테니 다들 조금만 더 힘내 주게.","JPN":"バレる前に早くオフィスを片付けよう。私も手伝うからみんな頑張ってくれたまえ。","ENG":"Why don't we tidy up the office before she catches on? I'll give you a hand as well. Hang in there.","TWN":"趁副總還沒來，趕緊整理一下辦公室吧。我也幫忙，大家再堅持一下。"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"정말요?! 고맙습니다, 사장님!","JPN":"本当ですか！？　ありがとうございます、社長！","ENG":"Really?! Thank you, Boss!","TWN":"真的？！謝謝你，老闆！"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_LONG","text":{"KOREA":"으허헉?! 내 3번 실린더가......!","JPN":"ぬおお！？　私の3番シリンダーが……！","ENG":"Eeep?! My third cylinder!","TWN":"啊啊啊？！我的3號圓筒……！"},"stage":{"bg":"OFFICE_MESSED","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_LONG","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_TANK_DAMAGE_DOWN"},{"id":"L33_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"또 고장나셨어요? 윤활유 뿌려드릴 테니까 이리로 돌아 보세요.","JPN":"また壊れちゃったんですか？　ほら、潤滑油を噴射するからこっちを向いてくださいね。","ENG":"Is it out of order again? I'll spray some lubricating oil on that. Turn around.","TWN":"又故障了嗎？請轉過來，我幫你上點潤滑油。"},"stage":{"bg":"OFFICE_MESSED","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_LONG","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L34_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"그리고 클로에, 사장님도 청소 중이시잖아.","JPN":"あとクロエ、社長も掃除中でしょう。","ENG":"And Chloe, even our Boss is helping out here.","TWN":"還有，克洛伊，沒看到老闆也在幫忙打掃嗎。"},"stage":{"bg":"OFFICE_MESSED","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_LONG","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L35_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"격납고로 갈 자재를 공방으로 보낸 건 너면서. 같이 도와 줘야지.","JPN":"格納庫に送る資材を工房に送ったのはクロエなんだから、一緒に手伝って。","ENG":"You're the one who sent the materials meant for the hangar to the workshop. You should help.","TWN":"明明是妳把要送到機庫的材料誤送到製造廠，還不快來幫忙。"},"stage":{"bg":"OFFICE_MESSED","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_LONG","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"CHLOE_COFFIN_NULL_NULL","text":{"KOREA":"이미 돕고 있습니다.","JPN":"すでに手伝っていますよ。","ENG":"I am helping.","TWN":"我已經在幫忙了。"},"stage":{"bg":"OFFICE_MESSED","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"CHLOE_COFFIN_NULL_NULL","text":{"KOREA":"제 수정구로 숨겨진 쓰레기들의 위치를 찾고 있죠.","JPN":"私の水晶玉で隠れたゴミの位置を特定しています。","ENG":"I'm using my crystal ball to find hidden trash.","TWN":"我正在用我的水晶球搜尋隱藏的垃圾。"},"stage":{"bg":"OFFICE_MESSED","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"CHLOE_COFFIN_NULL_NULL","text":{"KOREA":"앗! 저기 쇼파 뒤에 먹다 남은 쿠키 발견! 얼른 치우세요, 레나 양!","JPN":"あっ！　ソファーの後ろに食べ残しのクッキーを発見！　早く片付けてください、レナ！","ENG":"Oh! I found a half-eaten cookie behind the couch! Get rid of it, Lena!","TWN":"啊！沙發後面有吃剩的餅乾！快收拾呀，蕾娜！"},"stage":{"bg":"OFFICE_MESSED","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"야! 네가 무슨 공주님이야?","JPN":"ちょっと！　命令する立場じゃないでしょ？","ENG":"Hey! You think you're some kind of a princess?","TWN":"喂！妳以為自己是公主嗎？"},"stage":{"bg":"OFFICE_MESSED","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"쓰레기를 찾았으면 남에게 시키지 말고 직접 치우라고!","JPN":"ゴミを見つけたなら、人にやらせないで自分で片付けて！","ENG":"If you've found garbage, pick it up yourself!","TWN":"找到垃圾了就自己收拾，別使喚別人！"},"stage":{"bg":"OFFICE_MESSED","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"CHLOE_COFFIN_NULL_NULL","text":{"KOREA":"미, 미래를 관측하는 예언자에게 육체 노동은 금기입니다! 이 불신자!","JPN":"み、未来を観測する預言者にとって肉体労働は禁忌です！　この不届き者！","ENG":"H-how dare you tell a prophet to stoop so low as to engage in physical labor? Infidel!","TWN":"觀、觀測未來的預言者是不能做苦力的！妳這個非信徒！"},"stage":{"bg":"OFFICE_MESSED","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L45_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"너 정말!!","JPN":"ねえ！！　怒るよ！？","ENG":"Moron!","TWN":"妳！！"},"stage":{"bg":"OFFICE_MESSED","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L47_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"으음, 이래서는 끝이 없겠군.","JPN":"うむ、このままじゃキリがないな。","ENG":"Hmm. This will take forever at this rate.","TWN":"額，這樣什麼時候能收拾完。"},"stage":{"bg":"OFFICE_MESSED","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"할 수 없지. 비장의 수단을 쓰는 수밖에.","JPN":"仕方ない。奥の手を使うしかないか。","ENG":"Oh well. I suppose I'll have to turn to the last resort.","TWN":"沒辦法，只能用殺手鐧了。"},"stage":{"bg":"OFFICE_MESSED","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"비장의 수단? 그게 뭔가요?","JPN":"奥の手？　何でしょうか？","ENG":"Last resort? What's that?","TWN":"殺手鐧？什麼？"},"stage":{"bg":"OFFICE_MESSED","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"현대 산업의 꽃은 바로 아웃소싱!","JPN":"現代産業の偉大なシステム、つまりアウトソーシング！","ENG":"Outsourcing is the crown jewel of modern industry!","TWN":"現代產業佼佼者，外包！"},"stage":{"bg":"OFFICE_MESSED","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_TADA"},{"id":"L1_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"내부에 일할 사람이 부족하다면 외부에서 불러 오면 되지.","JPN":"社内が人手不足なら外部に頼むしかない。","ENG":"If we don't have enough manpower ourselves, we can always hire from the outside.","TWN":"明天開始如果內部人員不足，就叫外面的人吧。"},"stage":{"bg":"OFFICE_MESSED","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"마침 여기 전단지가 하나 떨어져 있군.","JPN":"ちょうどここにチラシがあったぞ。","ENG":"It just so happens that there's a flyer here.","TWN":"正好這裡有張傳單。"},"stage":{"bg":"OFFICE_MESSED","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"플로라 메이드 서비스라, 아주 훌륭한 청소업체일 것 같은 예감이 드는걸.","JPN":"フローラメイドサービスか。とても立派な清掃業者の予感がするな。","ENG":"Flora Maid Service? It sounds like a mighty fine cleaning company.","TWN":"芙蘿拉女僕服務？感覺是個很優秀的清潔公司。"},"stage":{"bg":"OFFICE_MESSED","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"아, 지난번에 클로에가 가져온 벼룩시장 신문에 껴 있던 광고 전단지네요.","JPN":"この前クロエが持ってきたフリーペーパーに紛れていたチラシですね。","ENG":"Oh, that's the flyer that fell out of the newspaper Chloe was reading.","TWN":"啊，上次克洛伊帶來了跳蚤市場報紙，裡面就夾著這個廣告傳單。"},"stage":{"bg":"OFFICE_MESSED","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"보고 나서 꼭 쓰레기통에 버리라고 했는데 역시나 이런 곳에 굴러다니고 있군요.","JPN":"読んだらちゃんと捨てなさいとあれだけ言ったのに、またこんな所に放置していて。","ENG":"I told her to toss it in the trash once she was done reading, but I'm not surprised she didn't.","TWN":"我明明叮囑過看完之後就要扔到垃圾桶裡，果不其然，她沒有扔到垃圾桶裡。"},"stage":{"bg":"OFFICE_MESSED","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"하아......","JPN":"はあ……","ENG":"*Sigh*","TWN":"哈啊……"},"stage":{"bg":"OFFICE_MESSED","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"뭐 이런 것도 다 인연이라고 할 수 있지.","JPN":"まあ、これも何かの縁かもしれない。","ENG":"Perhaps this was destined by fate.","TWN":"只能說這是緣分吧。"},"stage":{"bg":"OFFICE_MESSED","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"자네가 한 번 연락해 보겠나?","JPN":"一度問い合わせしてくれないか？","ENG":"Why don't you give them a call?","TWN":"妳聯繫一下吧？"},"stage":{"bg":"OFFICE_MESSED","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"알겠습니다. 멀쩡한 사람들이 오면 좋겠네요.","JPN":"わかりました。まともな業者だったらいいですね。","ENG":"Will do. I just hope we don't end up with more weirdos.","TWN":"好的，希望是一些正常人。"},"stage":{"bg":"OFFICE_MESSED","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"플로라 메이드 서비스를 이용해 주셔서 감사드립니다, 주인님.","JPN":"フローラメイドサービスをご利用いただきありがとうございます、ご主人様。","ENG":"Thank you for calling the Flora Maid Service, Master.","TWN":"感謝您使用芙蘿拉女僕服務，主人。"},"stage":{"bg":"OFFICE_MESSED","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_02"},{"id":"L14_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"부족한 몸이지만 메이드장을 맡고 있습니다. 베로니카라고 불러 주시길.","JPN":"不肖ながらメイド長を務めております。ベロニカとお呼びください。","ENG":"I humbly present myself as the Chief Maid. Please call me Veronica.","TWN":"我是女僕長貝洛妮卡，請多多關照。"},"stage":{"bg":"OFFICE_MESSED","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"TONFA_MAID_NULL_NULL","text":{"KOREA":"빨래 담당 모네라고 함다! 잘 부탁드리겠슴다!","JPN":"洗濯担当のモネっす！　よろしくっす！","ENG":"And I'm Mone, responsible for the laundry! Pleasure to meet you, sir!","TWN":"我是負責洗衣服的莫妮！請多多關照！"},"stage":{"bg":"OFFICE_MESSED","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_PRIDE"}}},"sfx":"FX_CUTSCEN_WIND2"},{"id":"L20_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"사장님. 저기 그...... 코스프레? 그런 쪽 분들 아니에요?","JPN":"社長、あの……コスプレ？　そっち系の人なのでは？","ENG":"Boss... Aren't these folks some kind of cosplayers?","TWN":"老闆，那個……她們是不是愛好角色扮演的那些人啊？"},"stage":{"bg":"OFFICE_MESSED","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L21_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"그, 그러게나 말일세.","JPN":"そ、そうだな。","ENG":"I-I was wondering the same thing.","TWN":"也、也許吧。"},"stage":{"bg":"OFFICE_MESSED","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"전단지에 메이드라고 적혀 있었다지만 정말 메이드가 올 줄이야......","JPN":"チラシには確かにメイドと書いてはあったが、まさか本物のメイドが来るとはな……","ENG":"It did say \\"maid\\" in the flyer, but I wasn't expecting actual maids...","TWN":"傳單上雖寫的是女僕，沒想到真的來了女僕……"},"stage":{"bg":"OFFICE_MESSED","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"인사드리면서 잠시 살펴 본 결과, 근무 환경으로는 부적절하군요.","JPN":"先ほど挨拶する際に周りを拝見しましたが、失礼ながら就労環境に適しているとは言えない状況ですね。","ENG":"I took a quick look around the place during the formalities, and I must say it's in a rather inadequate shape for work.","TWN":"我剛剛看了一下，這個環境並不適合辦公。"},"stage":{"bg":"OFFICE_MESSED","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"균열이 일어난 벽. 방치하면 곧 악취가 풍길 것 같은 세면대. 그리고 타일이 떨어진 천장까지.","JPN":"ひび割れた壁、放置しすぎて悪臭が漂ってそうな洗面台 、そしてタイルが剝がれ落ちた天井。","ENG":"Those cracks in the walls... the grimy sinks... and the ceiling tiles barely hanging on...","TWN":"龜裂的牆、感覺馬上會散發惡臭的洗臉台、以及掉了磚的天花板。"},"stage":{"bg":"OFFICE_MESSED","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"정리정돈에 앞서 노후화된 인테리어와 수도 시설을 정비해야겠습니다.","JPN":"整理整頓の前に、老朽化したインテリアや水道施設を整備しなければなりませんね。","ENG":"Before we begin tidying up, we'll have to repair the dilapidated plumbing and walls.","TWN":"在清掃之前，需要先整頓陳舊的室內裝飾和自來水設施。"},"stage":{"bg":"OFFICE_MESSED","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"연락을 받고 준비한 이 건물의 설계 도면입니다. 확인해 주시길.","JPN":"連絡を受けて用意したこの建物の設計図です。ご確認くださいませ。","ENG":"I've prepared a blueprint for this building when you reached out. Please have a look.","TWN":"這是我接到你們的電話之後拿到的建築設計圖，請你們過目。"},"stage":{"bg":"OFFICE_MESSED","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"......복장이랑 다르게 관리부장님처럼 프로페셔널한 사람이네요?","JPN":"……服装からは想像できないですが、仕事は管理部長級のプロフェッショナルな方のようですね。","ENG":"She's as professional as the Manager. I must say the costume was a bit misleading.","TWN":"……真是人不可貌相，居然是和管理部長一樣的專業人士呢？"},"stage":{"bg":"OFFICE_MESSED","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L31_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"상황이 그렇다지만, 일거리가 너무 많아질 텐데 기한 내에 가능하겠나?","JPN":"こんな状況で全て解決するのは大変だと思うんだが、期限内に対応できるかね？","ENG":"As worn down as this place is, fixing it all will be a lot of work. Can you get it all done on time?","TWN":"妳說的沒錯，但這樣一來事情就非常多了，可以在期限內完成嗎？"},"stage":{"bg":"OFFICE_MESSED","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"일정에 대해선 염려 마시길. 오늘 내로 평온한 일상을 보내실 수 있게 힘쓰겠습니다.","JPN":"日程についてはご心配なく。本日中に快適な職場環境に改善できるように努めます。","ENG":"Don't worry about the timeline. We'll make sure you're nice and comfortable by the end of today.","TWN":"日程方面您不用擔心，我會努力在今天內讓你們度過平靜的日常。"},"stage":{"bg":"OFFICE_MESSED","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"오늘 내로? 정말인가?","JPN":"今日中に？　本当か？","ENG":"You can finish within the day? Really?","TWN":"今天？你確定？"},"stage":{"bg":"OFFICE_MESSED","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L37_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"주인님께서 명령해 주신다면 기꺼이 이루어 드리겠습니다.","JPN":"ご主人様の命令なら喜んで叶えてさしあげます。","ENG":"Anything is possible as long as you give the order, Master.","TWN":"只要主人下命令，我會盡全力滿足您的。"},"stage":{"bg":"OFFICE_MESSED","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L38_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"으흠......","JPN":"ほお……","ENG":"Hmm...","TWN":"嗯……"},"stage":{"bg":"OFFICE_MESSED","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L39_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"좋네! 부탁하지!","JPN":"いいだろう！　頼んだぞ！","ENG":"Very well! Please get it done then!","TWN":"好吧！那就拜託妳們了！"},"stage":{"bg":"OFFICE_MESSED","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"들었죠, 모네? 주인님께서 믿고 맡겨 주신 만큼 최선을 다하기로 하죠.","JPN":"聞きましたか、モネ？　ご主人様が信頼して仕事を任せてくださったのです、最善を尽くしましょう。","ENG":"Hear that, Mone? The Master has entrusted us with this task. We must strive to do our best.","TWN":"聽見了吧，莫妮？主人這麼信任我們，我們一定要全力以赴。"},"stage":{"bg":"OFFICE_MESSED","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L43_1","type":"dialog","speaker":"TONFA_MAID_NULL_NULL","text":{"KOREA":"넵! 모네만 믿고 계시지 말임다!","JPN":"はいっ！　モネにお任せくださいっす！","ENG":"Will do! You can count on Mone!","TWN":"好的！就交給莫妮吧！"},"stage":{"bg":"OFFICE_MESSED","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};